import{_ as l,C as n,c as p,o,a8 as e,j as t,a,G as r}from"./chunks/framework.Boywj_Hd.js";const d="/sealdice-manual-next/assets/dbtransfer-1.YxnftyxI.png",c="/sealdice-manual-next/assets/dbtransfer-2.DDhoCG0x.png",h="/sealdice-manual-next/assets/dbtransfer-4.DgucEc_k.png",m="/sealdice-manual-next/assets/dbtransfer-5.GdxeOJY0.png",u="/sealdice-manual-next/assets/dbtransfer-6.DDfo_tYe.png",k="/sealdice-manual-next/assets/dbtransfer-7.DF1gR9CZ.png",g="/sealdice-manual-next/assets/dbtransfer-8.7YLUEc3d.png",b="/sealdice-manual-next/assets/dbtransfer-9.DGyHuXhE.png",y="/sealdice-manual-next/assets/dbtransfer-10.CPmzJ6KT.png",S="data:image/png;base64,",E="/sealdice-manual-next/assets/dbtransfer-12.DqPHQ7BC.png",v="/sealdice-manual-next/assets/dbtransfer-13.C3piOSVG.png",L="/sealdice-manual-next/assets/dbtransfer-14.DSbZB7gZ.png",Q="/sealdice-manual-next/assets/dbtransfer-20.ClhpLFxb.png",f="/sealdice-manual-next/assets/dbtransfer-19.Bi5Tqz-E.png",q="/sealdice-manual-next/assets/dbtransfer-21.-QApCEje.png",x="/sealdice-manual-next/assets/dbtransfer-22.D7gfOMwz.png",A="/sealdice-manual-next/assets/dbtransfer-23.DeC0HAc3.png",D="/sealdice-manual-next/assets/dbtransfer-24.ioV4y-BB.png",U=JSON.parse('{"title":"其他数据库的连接","description":"","frontmatter":{"lang":"zh-cn","title":"其他数据库的连接"},"headers":[],"relativePath":"deploy/db-transfer.md","filePath":"deploy/db-transfer.md","lastUpdated":1750875084000}'),C={name:"deploy/db-transfer.md"};function w(B,s,T,I,M,F){const i=n("Badge");return o(),p("div",null,[s[8]||(s[8]=e('<h1 id="其他数据库的连接" tabindex="-1">其他数据库的连接 <a class="header-anchor" href="#其他数据库的连接" aria-label="Permalink to &quot;其他数据库的连接&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">本节内容</p><p>本节将介绍用户如何使用海豹连接 MySQL 数据库，此教程亦适用于 MariaDB 数据库。</p></div><div class="warning custom-block"><p class="custom-block-title">注意：</p><p>我们认为，大部分情况下，优化过的 SQLite 数据库已足够用户使用，需要更换数据库的用户应该认为目前海豹的 SQLite 数据库无法满足他的需求。</p><p>所以，我们默认观看本节的用户对数据库有一定了解，并存在一定的计算机编程知识或计算机使用知识。</p><p>如你不具备相应知识，那么本节可能无法给你有用的帮助。</p></div><div class="danger custom-block"><p class="custom-block-title">警告：</p><p>MySQL 尚未经过大批量数据测试。由于 MySQL 的联合索引长度问题，MySQL 的联合索引均未创建，这可能会导致性能下降！</p><p>另外，创建数据库需要用户自行注意数据库连接安全，请务必设置较强密码以防止数据丢失！</p></div><h2 id="海豹支持的数据库系统" tabindex="-1">海豹支持的数据库系统 <a class="header-anchor" href="#海豹支持的数据库系统" aria-label="Permalink to &quot;海豹支持的数据库系统&quot;">​</a></h2>',5)),t("p",null,[s[0]||(s[0]=a("从 ")),r(i,{type:"tip",text:"v1.5.0"}),s[1]||(s[1]=a(" 起，除原有的 ")),s[2]||(s[2]=t("code",null,"SQLite",-1)),s[3]||(s[3]=a(" 数据库外，海豹新支持了 ")),s[4]||(s[4]=t("code",null,"MySQL",-1)),s[5]||(s[5]=a("、")),s[6]||(s[6]=t("code",null,"PostgresSQL（ PGSQL ）",-1)),s[7]||(s[7]=a("的连接。"))]),s[9]||(s[9]=e('<p>你可以通过修改 <code>.env</code> 文件以切换至海豹支持的其他数据库。</p><p>下面，我们详细对 MySQL 数据库与 PostgresSQL（PGSQL）数据库同海豹的对接进行讲解。</p><h2 id="对接-mysql" tabindex="-1">对接 MySQL <a class="header-anchor" href="#对接-mysql" aria-label="Permalink to &quot;对接 MySQL&quot;">​</a></h2><h3 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h3><h4 id="安装-mysql" tabindex="-1">安装 MySQL <a class="header-anchor" href="#安装-mysql" aria-label="Permalink to &quot;安装 MySQL&quot;">​</a></h4><p>请跟随下方的安装方式，安装对应你所使用的平台的 MySQL/MariaDB:</p><p><a href="https://www.runoob.com/mysql/mysql-install.html" target="_blank" rel="noreferrer">https://www.runoob.com/mysql/mysql-install.html</a></p><p>安装时，其要求你输入密码，记下该密码，并供使用。</p><h4 id="选择合适的-db-工具" tabindex="-1">选择合适的 DB 工具 <a class="header-anchor" href="#选择合适的-db-工具" aria-label="Permalink to &quot;选择合适的 DB 工具&quot;">​</a></h4><p>由于大部分用户并不擅长非图形化页面的操作，此处提供一个可视化工具供使用，本教程选用 <code>squirrelsql</code> 作为可视化工具。</p><p>本教程主要服务于 Windows Server 用户，其他用户可自行按照原理使用 SQL 命令来创建等效的数据库。</p><p>在 这里 下载定制好的 <code>squirrelsql</code>。该 <code>squirrelsql</code> 设置为开箱即用，允许修改 SQLite/MySQL/PostgreSQL 三种类型的数据库。请将 <code>squirrelsql</code> 放置在和 MySQL 相同的服务器上。</p><h4 id="创建数据库" tabindex="-1">创建数据库 <a class="header-anchor" href="#创建数据库" aria-label="Permalink to &quot;创建数据库&quot;">​</a></h4><p>我们需要为我们的海豹创建一个单独的数据库，这里的概念比较抽象：</p><p>一个 MySQL 数据库 可以创建多个 &quot;DataBase（数据库）&quot;</p><p>在后文中，提及数据库的若无 MySQL 前缀，均认为是 &quot;database&quot; 数据库。</p><p>一个数据库对应一个海豹实例，也就是说一个 MySQL 数据库可以支持多个数据库，进而支持多个海豹的实例。</p><p>详细细节可以参考如下链接 <a href="https://www.runoob.com/mysql/mysql-create-database.html" target="_blank" rel="noreferrer">https://www.runoob.com/mysql/mysql-create-database.html</a></p><p>此处以创建 &quot;seal&quot; 数据库为例，进行数据库的创建。首先启动 Squirrel SQL，页面如图所示：</p><img src="'+d+'" alt="创建连接-STEP 1" width="65%"><p>单击左侧的别名，而后点击加号：</p><img src="'+c+'" alt="创建连接-STEP 2" width="65%"><p>驱动程序选择 MySQL Driver，名称填写任意名称。此处选择填写“SealDice-01”。地址按如下填写</p><div class="language-CONFIG vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">CONFIG</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>jdbc:mysql://127.0.0.1:3306/?charset=utf8mb4&amp;parseTime=True&amp;loc=Local</span></span></code></pre></div><p>用户名和密码填写在 安装 MySQL 时输入的用户名和密码。而后点击连接，连接后的页面如图所示：</p><img src="'+h+'" alt="连接 MySQL 数据库到可视化工具" width="65%"><p>我们要创建一个数据库，在左侧树状部分随意右键 - 创建数据库：</p><img src="'+m+'" alt="创建数据库" width="65%"><p>输入名称：seal 后点击确定：</p><img src="'+u+'" alt="创建数据库" width="65%"><p>之后我们将看到新的数据库被创建出来：</p><img src="'+k+'" alt="创建完成的数据库" width="65%"><h3 id="创建-mysql-用户-非必选" tabindex="-1">创建 MySQL 用户（非必选） <a class="header-anchor" href="#创建-mysql-用户-非必选" aria-label="Permalink to &quot;创建 MySQL 用户（非必选）&quot;">​</a></h3><p>你可以使用 root 用户直接连接 MySQL，但这是不推荐的，尤其是在你要多个骰子共用同一个数据库的情况。更多情况下，我们会创建一个额外的新用户，以保证数据库安全。</p><p>我们采用创建 &quot;sealdice&quot; 用户，密码为 &quot;Sealdice123!&quot; 的方式来进行教学。SQuirrel SQL 不支持直接 GUI 创建用户，我们需要使用 SQL 面板来创建一个新用户。</p><p>单击 SQL 面板，切换到 SQL 模式：</p><img src="'+g+'" alt="切换到 SQL 模式" width="65%"><p>切换到 SQL 模式后，可以稍微拖拉拽一下，让这个 SQL 面板变大：</p><img src="'+b+'" alt="调整 SQL 面板" width="65%"><p>在此处输入如下内容：</p><div class="language-SQL vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">SQL</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> USER</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &#39;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sealdice</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&#39;@</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;localhost&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> IDENTIFIED </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">BY</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Sealdice123!&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>注意，不可省略分号，分号必须输入，这里所有的符号都是英文字符。</p><div class="tip custom-block"><p class="custom-block-title">提示：</p><p>如果需要在其他地址访问，可以替换 <code>localhost</code> 为其他的 IP；若需要所有主机都能访问，则将其替换成一个 <code>%</code> 。</p></div><div class="danger custom-block"><p class="custom-block-title">警告：保护好自己的数据库</p><p>使用弱密码 + 暴露到公网（所有主机都可访问加开放端口）有极大概率会导致你的数据丢失！请注意保护自己的数据库</p></div><p>而后，单击运行 SQL 按钮运行 SQL :</p><img src="'+y+'" alt="执行 SQL " width="65%"><p>当看到如下提示，证明 SQL 执行成功：</p><img src="'+S+'" alt="SQL 运行成功" width="65%"><p>这时，可切换回对象选项卡，在 <code>USERS</code> 处右键 - 刷新缓存，查看新创建的用户：</p><img src="'+E+`" alt="查看新创建的用户" width="65%"><p>接下来，我们要将刚刚我们创建的数据库“分配”给这个用户，切换到 SQL 选项卡，输入如下的 SQL：</p><div class="language-SQL vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">SQL</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 授予 sealdice@localhost 对 seal 库的所有权限</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GRANT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ALL PRIVILEGES </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> seal.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;sealdice&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;localhost&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><div class="language-SQL vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">SQL</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 刷新权限（使更改生效）</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">FLUSH PRIVILEGES;</span></span></code></pre></div><p>请注意：如果你在前文中，修改了 localhost 为其他地址，你需要在这里一并修改。在 MySQL 中，他们被视为不同的用户权限。</p><p>而后，将上面的所有 SQL 语句全部选中后单击运行按钮（若不全选，有可能只执行其中一个）：</p><img src="`+v+'" alt="执行 SQL" width="65%"><p>同样的，可以在最下方查看结果：</p><img src="'+L+`" alt="查看结果" width="65%"><h4 id="使用海豹进行连接" tabindex="-1">使用海豹进行连接 <a class="header-anchor" href="#使用海豹进行连接" aria-label="Permalink to &quot;使用海豹进行连接&quot;">​</a></h4><p>解压一个成品海豹，并在目录下创建 <code>.env</code> 文件（注意，在 env 前有一个点，请勿漏写）：</p><div class="tip custom-block"><p class="custom-block-title">提示：</p><p>如已创建了 <code>.env</code> ，最后却不生效，请检查拓展名是否改对，你可以直接在 Squirrel SQL 里复制一个 <code>.env</code> 文件。</p></div><p>在 <code>.env</code> 文件中填写如下内容：</p><div class="language-.env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">.env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DB_TYPE=mysql</span></span>
<span class="line"><span>DB_DSN=&quot;sealdice:Sealdice123!@tcp(127.0.0.1:3306)/seal?charset=utf8mb4&amp;parseTime=True&amp;loc=Local&quot;</span></span></code></pre></div><img src="`+Q+'" alt="填写文件" width="65%"><p>而后，保存并运行海豹。</p><p>其中，<code>sealdice</code> 和 <code>Sealdice123!</code> 为创建的新用户的用户名和密码。seal 为数据库名。如果您没有创建新用户，使用 root 和你设置的密码。</p><div class="warning custom-block"><p class="custom-block-title">注意：</p><p>如果你需要从一个有数据的海豹迁移，在操作这个步骤前，请先将目录下的 upgrade_metadata.json 改名为其他名称，否则，150 版本的海豹数据库将无法正常创建！</p></div><p>如果没有意外，你的海豹应当正常加载了 MySQL 数据库：</p><img src="'+f+'" alt="加载成功" width="65%"><img src="'+q+'" alt="加载成功" width="65%"><p>在对应的 seal 数据库下，也能查看到对应的 TABLE (请记得刷新)：</p><img src="'+x+'" alt="检查数据库" width="65%"><p>若需要查看数据，可以点击内容：</p><img src="'+A+'" alt="检查数据库" width="65%"><p>如果注意到某些数据是二进制的，双击如图所示的数据，并单击 <code>Reformat</code> ：</p><img src="'+D+'" alt="检查数据库" width="65%"><p>即可查看数据的信息。</p>',77))])}const K=l(C,[["render",w]]);export{U as __pageData,K as default};
